solution:
apiVersion: v1
kind: ConfigMap
metadata:
  name: ecr-cross-account-policy
  namespace: default
data:
  policy.json: |
    {
      "Version": "2012-10-17",
      "Statement": [
        {
          "Sid": "CrossAccountPull",
          "Effect": "Allow",
          "Principal": {
            "AWS": "arn:aws:iam::999888777666:root"
          },
          "Action": [
            "ecr:GetDownloadUrlForLayer",
            "ecr:BatchGetImage",
            "ecr:BatchCheckLayerAvailability"
          ]
        }
      ]
    }
